// Helper map for O(1) lookups
export const STATE_DATA_MAP: Record<string, NigerianStateData> = Object.fromEntries(
  NIGERIAN_STATES_DATA.map((s) => [s.slug, s])
);

// Region groupings for the index page
export const REGION_GROUPS: Array<{ region: string; states: NigerianStateData[] }> = [
  'South West', 'South East', 'South South', 'North Central', 'North West', 'North East', 'FCT'
].map((region) => ({
  region,
  states: NIGERIAN_STATES_DATA.filter((s) => s.region === region),
}));
